import{_ as a,o as e,c as t,a2 as s}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"新加坡余额通","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/sg-cash-plus.md","filePath":"zh-CN/funds-and-wealth/sg-cash-plus.md"}'),i={name:"funds-and-wealth/sg-cash-plus.md"};function p(r,l,u,n,o,d){return e(),t("div",null,[...l[0]||(l[0]=[s('<h1 id="新加坡余额通" tabindex="-1">新加坡余额通 <a class="header-anchor" href="#新加坡余额通" aria-label="Permalink to &quot;新加坡余额通&quot;">​</a></h1><p>场景：余额通 - 余额通、货币基金、闲置资金、新加坡账户</p><p>用户可能问：新加坡余额通支持哪些币种、余额通怎么开通、手动赎回后多久到账、余额通资金能直接买股票吗、余额通收益什么时候到账</p><p>新加坡余额通适用于长桥新加坡账户，支持新币（SGD）和美元（USD）两种币种，将闲置资金自动投入货币基金获取收益。</p><p>开通与自动转入：</p><ul><li>签署授权后，闲置资金自动转入货币基金</li><li>起投金额 0.01</li></ul><p>自动赎回：</p><ul><li>买股票、认购新股等需要扣款时，系统自动从货币基金赎回所需金额</li></ul><p>手动赎回规则：</p><ul><li>交易日 10:00 前提交赎回申请，当日处理</li><li>手动赎回后，3 个自然日内不会自动转入</li><li>赎回资金可立即用于股票交易、新股认购、换汇、出金</li></ul><p>交易时间：每天 10:00 自动转入和转出。</p><p>收益周期：</p><ul><li>T 日 10:00 前转入 → T+1 日确认份额 → T+2 日派发收益</li></ul><p>关闭余额通：</p><ul><li>关闭后，系统在最近交易日赎回持仓，最晚 T+1 到账</li></ul>',15)])])}const h=a(i,[["render",p]]);export{c as __pageData,h as default};
